 68→void ALFPHexTile::InitializeEdgeComponents(UPaperSprite* EdgeSprite, UPaperSprite* OverlaySprite, float InHexSize, float InVerticalScale)
 69→{
 70→	// 设置覆盖层精灵
 71→	if (OverlaySpriteComponent && OverlaySprite)
 72→	{
 73→		OverlaySpriteComponent->SetSprite(OverlaySprite);
 74→		OverlaySpriteComponent->SetVisibility(false);
 75→		OverlaySpriteComponent->SetRelativeRotation(FRotator(0, 0, 90.f));
 76→	}
 77→
 78→	// 计算每条边的位置和旋转（平顶六边形，30° 偏移，与 DrawDebugHexagon 一致）
 79→	const float AngleOffset = 30.0f;
 80→	const float HorizontalRadius = InHexSize;
 81→	const float VerticalRadius = InHexSize * InVerticalScale;
 82→
 83→	for (int32 i = 0; i < 6; i++)
 84→	{
 85→		if (!EdgeSpriteComponents.IsValidIndex(i) || !EdgeSpriteComponents[i]) continue;
 86→
 87→		// 顶点 i 和 顶点 (i+1)%6
 88→		float Angle1 = FMath::DegreesToRadians(60.0f * i + AngleOffset);
 89→		float Angle2 = FMath::DegreesToRadians(60.0f * ((i + 1) % 6) + AngleOffset);
 90→
 91→		FVector V1(HorizontalRadius * FMath::Cos(Angle1), VerticalRadius * FMath::Sin(Angle1), 0);
 92→		FVector V2(HorizontalRadius * FMath::Cos(Angle2), VerticalRadius * FMath::Sin(Angle2), 0);
 93→
 94→		// 边中点
 95→		FVector Midpoint = (V1 + V2) * 0.5f;
 96→		Midpoint.Z = 1.0f; // 在装饰层之上
 97→
 98→		// 边方向角度
 99→		FVector EdgeDir = V2 - V1;
100→		float EdgeAngle = FMath::RadiansToDegrees(FMath::Atan2(EdgeDir.Y, EdgeDir.X));
101→
102→		EdgeSpriteComponents[i]->SetSprite(EdgeSprite);
103→		EdgeSpriteComponents[i]->SetRelativeLocation(Midpoint);
104→		// Paper2D 精灵在 XY 平面旋转，使用 Yaw（绕 Z 轴）
105→		EdgeSpriteComponents[i]->SetRelativeRotation(FRotator(0, EdgeAngle, 90.f));
106→		EdgeSpriteComponents[i]->SetVisibility(false);
107→
108→		// 根据边长缩放精灵（假设精灵原始宽度覆盖标准边长）
109→		float EdgeLength = EdgeDir.Size();
110→		// 缩放将在配置精灵资产后根据实际尺寸调整
111→	}
112→}
